import urllib.parse
# Test for case variations of forbidden keywords
words = ['union', 'select', 'or', 'and']
payloads = []
for w in words:
    for c in range(len(w)):
        s = w[:c] + w[c].upper() + w[c+1:]
        payloads.append(f"' {s} 1=1-- -")
for p in payloads:
    print(urllib.parse.quote(p))
